export type MushroomCategory = 'jestiva' | 'nejestiva' | 'smrtonosna';

export interface MushroomSection {
  id: string;
  name: string;
  latinFamily: string;
  description: string;
}

export interface Mushroom {
  id: number;
  name: string;
  latinName: string;
  category: MushroomCategory;
  section: string;
  activeMonths: number[];
  cap: string;
  gills: string;
  stem: string;
  flesh: string;
  spores: string;
  habitat: string;
  edibility: string;
  notes: string;
  image: string;
  images: string[];
  confidence: number;
}

export const MONTHS_SR = ['Jan', 'Feb', 'Mar', 'Apr', 'Maj', 'Jun', 'Jul', 'Avg', 'Sep', 'Okt', 'Nov', 'Dec'];

const GITHUB_BASE = 'https://raw.githubusercontent.com/DBrka/Mushroom-App/main/images';
const imgs = (id: number, n = 8): string[] =>
  Array.from({ length: n }, (_, i) => `${GITHUB_BASE}/mushrooms/m${id}_${String(i + 1).padStart(2, '0')}.jpg`);

